-- ANGELCARE Revenue Command OS — Mega ZIP 3
-- Revenue Doctrine & Institutional Memory
-- Cumulative over Phase 1 Foundation and Phase 2 Revenue Digital Twin

begin;
create extension if not exists pgcrypto;

create or replace function public.revenue_os_touch_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at = timezone('utc', now()); return new; end $$;

create table if not exists public.revenue_os_knowledge_domains (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, description text not null default '',
  owner_role text not null default '', business_unit_codes jsonb not null default '[]'::jsonb, status text not null default 'active',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_doctrines (
  id uuid primary key default gen_random_uuid(), code text not null unique, title text not null, summary text not null default '',
  knowledge_type text not null, owner_role text not null default '', department text not null default '', business_unit_codes jsonb not null default '[]'::jsonb,
  status text not null default 'draft' check(status in ('draft','in-review','approved','effective','suspended','retired','rejected')),
  confidentiality text not null default 'internal' check(confidentiality in ('public','internal','confidential','restricted')),
  version text not null default '1.0', effective_from date, effective_to date, next_review_at date, review_cycle_days integer not null default 90,
  supersedes_code text, applicable_command_families jsonb not null default '[]'::jsonb, applicable_segment_codes jsonb not null default '[]'::jsonb,
  applicable_offer_codes jsonb not null default '[]'::jsonb, tags jsonb not null default '[]'::jsonb, source_authority text not null default '',
  content_blocks jsonb not null default '[]'::jsonb, rules jsonb not null default '[]'::jsonb, evidence_refs jsonb not null default '[]'::jsonb,
  source text not null default 'manual', created_by uuid, created_by_label text, metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);
create index if not exists revenue_os_doctrines_status_idx on public.revenue_os_doctrines(status);
create index if not exists revenue_os_doctrines_type_idx on public.revenue_os_doctrines(knowledge_type);
create index if not exists revenue_os_doctrines_tags_gin on public.revenue_os_doctrines using gin(tags);
create index if not exists revenue_os_doctrines_business_units_gin on public.revenue_os_doctrines using gin(business_unit_codes);

create table if not exists public.revenue_os_knowledge_versions (
  id uuid primary key default gen_random_uuid(), resource_type text not null, resource_code text not null, version text not null,
  status text not null default 'draft', change_reason text not null default '', snapshot jsonb not null default '{}'::jsonb, snapshot_hash text not null,
  created_by uuid, created_by_label text not null default '', approved_by uuid, approved_by_label text, approved_at timestamptz,
  created_at timestamptz not null default timezone('utc',now()), unique(resource_type,resource_code,version)
);

create table if not exists public.revenue_os_doctrine_sections (
  id uuid primary key default gen_random_uuid(), doctrine_code text not null references public.revenue_os_doctrines(code) on update cascade on delete cascade,
  section_code text not null, heading text not null, body text not null default '', sequence_order integer not null default 1, block_type text not null default 'principle',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now()), unique(doctrine_code,section_code)
);

create table if not exists public.revenue_os_doctrine_rules (
  id uuid primary key default gen_random_uuid(), doctrine_code text not null references public.revenue_os_doctrines(code) on update cascade on delete cascade,
  rule_code text not null, name text not null, condition_expression text not null default '', required_action text not null default '', prohibited_action text,
  escalation_role text, severity text not null default 'medium', machine_enforceable boolean not null default false,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now()), unique(doctrine_code,rule_code)
);

create table if not exists public.revenue_os_decision_trees (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, doctrine_code text references public.revenue_os_doctrines(code) on update cascade,
  objective text not null default '', root_node_code text, status text not null default 'draft', version text not null default '1.0', nodes jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_knowledge_assets (
  id uuid primary key default gen_random_uuid(), code text not null unique, title text not null, asset_type text not null, description text not null default '',
  owner_role text not null default '', business_unit_codes jsonb not null default '[]'::jsonb, confidentiality text not null default 'internal',
  status text not null default 'draft', version text not null default '1.0', effective_from date, source_uri text, file_name text, mime_type text,
  checksum text, page_count integer, language text not null default 'fr', tags jsonb not null default '[]'::jsonb,
  linked_doctrine_codes jsonb not null default '[]'::jsonb, index_status text not null default 'not-indexed', chunk_count integer not null default 0,
  source text not null default 'manual', metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);
create index if not exists revenue_os_knowledge_assets_status_idx on public.revenue_os_knowledge_assets(status,index_status);
create index if not exists revenue_os_knowledge_assets_tags_gin on public.revenue_os_knowledge_assets using gin(tags);

create table if not exists public.revenue_os_knowledge_asset_versions (
  id uuid primary key default gen_random_uuid(), asset_code text not null references public.revenue_os_knowledge_assets(code) on update cascade on delete cascade,
  version text not null, checksum text, metadata jsonb not null default '{}'::jsonb, status text not null default 'draft',
  created_by uuid, created_by_label text, created_at timestamptz not null default timezone('utc',now()), unique(asset_code,version)
);

create table if not exists public.revenue_os_knowledge_chunks (
  id uuid primary key default gen_random_uuid(), asset_code text not null references public.revenue_os_knowledge_assets(code) on update cascade on delete cascade,
  chunk_index integer not null, heading text, content text not null, token_estimate integer not null default 0, confidentiality text not null default 'internal',
  metadata jsonb not null default '{}'::jsonb, content_hash text not null, created_at timestamptz not null default timezone('utc',now()), unique(asset_code,chunk_index)
);

create table if not exists public.revenue_os_knowledge_relationships (
  id uuid primary key default gen_random_uuid(), code text not null unique, source_type text not null, source_code text not null,
  relationship_type text not null, target_type text not null, target_code text not null, rationale text not null default '', active boolean not null default true,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_sales_scripts (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, channel text not null, stage text not null default '',
  segment_codes jsonb not null default '[]'::jsonb, offer_codes jsonb not null default '[]'::jsonb, objective text not null default '',
  opening text not null default '', body text not null default '', call_to_action text not null default '', fallback text not null default '',
  prohibited_claims jsonb not null default '[]'::jsonb, required_personalization_fields jsonb not null default '[]'::jsonb,
  status text not null default 'draft', version text not null default '1.0', owner_role text not null default '',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_objection_patterns (
  id uuid primary key default gen_random_uuid(), code text not null unique, objection text not null, category text not null,
  segment_codes jsonb not null default '[]'::jsonb, offer_codes jsonb not null default '[]'::jsonb,
  diagnostic_questions jsonb not null default '[]'::jsonb, response_framework jsonb not null default '[]'::jsonb,
  evidence_refs jsonb not null default '[]'::jsonb, escalation_trigger text not null default '', prohibited_response text not null default '',
  status text not null default 'draft', created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_case_studies (
  id uuid primary key default gen_random_uuid(), code text not null unique, title text not null, case_type text not null,
  business_unit_code text not null default '', segment_code text not null default '', market_code text not null default '',
  context text not null default '', problem text not null default '', actions jsonb not null default '[]'::jsonb, outcome text not null default '',
  measurable_signals jsonb not null default '{}'::jsonb, lessons jsonb not null default '[]'::jsonb, reusable_patterns jsonb not null default '[]'::jsonb,
  evidence_refs jsonb not null default '[]'::jsonb, status text not null default 'draft', confidentiality text not null default 'restricted',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_campaign_patterns (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, pattern_type text not null, objective text not null default '',
  applicability jsonb not null default '[]'::jsonb, sequence jsonb not null default '[]'::jsonb, required_signals jsonb not null default '[]'::jsonb,
  stop_conditions jsonb not null default '[]'::jsonb, success_metrics jsonb not null default '[]'::jsonb, risk_controls jsonb not null default '[]'::jsonb,
  status text not null default 'draft', version text not null default '1.0', created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_playbooks (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, objective text not null default '',
  business_unit_codes jsonb not null default '[]'::jsonb, segment_codes jsonb not null default '[]'::jsonb, trigger text not null default '',
  preconditions jsonb not null default '[]'::jsonb, steps jsonb not null default '[]'::jsonb, completion_rule text not null default '',
  escalation_policy text not null default '', status text not null default 'draft', version text not null default '1.0', owner_role text not null default '',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_policy_restrictions (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, restriction_type text not null,
  scope jsonb not null default '[]'::jsonb, rule text not null default '', prohibited_actions jsonb not null default '[]'::jsonb,
  required_approver_role text, escalation_path text not null default '', severity text not null default 'high', status text not null default 'draft', effective_from date,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_brand_requirements (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, scope jsonb not null default '[]'::jsonb,
  requirement text not null default '', allowed_patterns jsonb not null default '[]'::jsonb, prohibited_patterns jsonb not null default '[]'::jsonb,
  evidence_required jsonb not null default '[]'::jsonb, status text not null default 'draft',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_partner_benefits (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, segment_codes jsonb not null default '[]'::jsonb,
  offer_codes jsonb not null default '[]'::jsonb, value_statement text not null default '', eligibility_rules jsonb not null default '[]'::jsonb,
  validity_window text, approval_role text not null default '', communication_rules jsonb not null default '[]'::jsonb, status text not null default 'draft',
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_knowledge_approvals (
  id uuid primary key default gen_random_uuid(), code text not null unique, resource_type text not null, resource_code text not null, resource_version text not null,
  requested_by uuid, requested_by_label text not null default '', requested_at timestamptz not null default timezone('utc',now()), required_approver_role text not null,
  decision text not null default 'pending' check(decision in ('pending','approved','rejected','changes-requested','cancelled')),
  decided_by uuid, decided_by_label text, decided_at timestamptz, rationale text, checklist jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);
create index if not exists revenue_os_knowledge_approvals_pending_idx on public.revenue_os_knowledge_approvals(decision,requested_at);

create table if not exists public.revenue_os_knowledge_conflicts (
  id uuid primary key default gen_random_uuid(), code text not null unique, conflict_type text not null, left_resource_code text not null, right_resource_code text not null,
  summary text not null default '', risk text not null default '', recommended_resolution text not null default '',
  status text not null default 'open' check(status in ('open','under-review','resolved','accepted-risk','dismissed')),
  severity text not null default 'high', detected_at timestamptz not null default timezone('utc',now()), resolved_at timestamptz,
  resolved_by uuid, resolved_by_label text, resolution text, created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_knowledge_index_jobs (
  id uuid primary key default gen_random_uuid(), code text not null unique, asset_code text not null references public.revenue_os_knowledge_assets(code) on update cascade on delete cascade,
  requested_by uuid, requested_by_label text, requested_at timestamptz not null default timezone('utc',now()),
  status text not null default 'queued' check(status in ('not-indexed','queued','processing','indexed','failed','blocked')),
  chunk_count integer not null default 0, error text, completed_at timestamptz, metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now())
);

create table if not exists public.revenue_os_knowledge_validation_issues (
  id uuid primary key default gen_random_uuid(), code text not null, resource_type text not null, resource_code text not null, category text not null,
  severity text not null, title text not null, detail text not null default '', recommended_action text not null default '',
  status text not null default 'open' check(status in ('open','acknowledged','resolved','waived')), detected_at timestamptz not null default timezone('utc',now()),
  resolved_at timestamptz, resolved_by uuid, resolved_by_label text, created_at timestamptz not null default timezone('utc',now()), updated_at timestamptz not null default timezone('utc',now()),
  unique(code,resource_code)
);

create table if not exists public.revenue_os_knowledge_snapshots (
  id uuid primary key default gen_random_uuid(), snapshot_code text not null unique, release_code text not null, readiness_score integer not null default 0,
  snapshot jsonb not null default '{}'::jsonb, created_by uuid, created_by_label text, status text not null default 'needs-validation',
  created_at timestamptz not null default timezone('utc',now())
);

DO $$ declare t text; begin
  foreach t in array array[
    'revenue_os_knowledge_domains','revenue_os_doctrines','revenue_os_doctrine_sections','revenue_os_doctrine_rules','revenue_os_decision_trees',
    'revenue_os_knowledge_assets','revenue_os_knowledge_relationships','revenue_os_sales_scripts','revenue_os_objection_patterns','revenue_os_case_studies',
    'revenue_os_campaign_patterns','revenue_os_playbooks','revenue_os_policy_restrictions','revenue_os_brand_requirements','revenue_os_partner_benefits',
    'revenue_os_knowledge_approvals','revenue_os_knowledge_conflicts','revenue_os_knowledge_index_jobs','revenue_os_knowledge_validation_issues'
  ] loop
    execute format('drop trigger if exists %I_touch_updated_at on public.%I',t,t);
    execute format('create trigger %I_touch_updated_at before update on public.%I for each row execute function public.revenue_os_touch_updated_at()',t,t);
  end loop;
end $$;

DO $$ declare t text; begin
  foreach t in array array[
    'revenue_os_knowledge_domains','revenue_os_doctrines','revenue_os_knowledge_versions','revenue_os_doctrine_sections','revenue_os_doctrine_rules','revenue_os_decision_trees',
    'revenue_os_knowledge_assets','revenue_os_knowledge_asset_versions','revenue_os_knowledge_chunks','revenue_os_knowledge_relationships','revenue_os_sales_scripts',
    'revenue_os_objection_patterns','revenue_os_case_studies','revenue_os_campaign_patterns','revenue_os_playbooks','revenue_os_policy_restrictions',
    'revenue_os_brand_requirements','revenue_os_partner_benefits','revenue_os_knowledge_approvals','revenue_os_knowledge_conflicts',
    'revenue_os_knowledge_index_jobs','revenue_os_knowledge_validation_issues','revenue_os_knowledge_snapshots'
  ] loop
    execute format('alter table public.%I enable row level security',t);
    execute format('revoke all on table public.%I from anon, authenticated',t);
    execute format('grant all on table public.%I to service_role',t);
  end loop;
end $$;

on conflict(permission_key) do update set label=excluded.label,description=excluded.description,risk_class=excluded.risk_class,active=true,updated_at=timezone('utc',now());

on conflict(flag_key) do update set label=excluded.label,description=excluded.description,enabled=excluded.enabled,locked=excluded.locked,risk_class=excluded.risk_class,updated_at=timezone('utc',now());

values('memory-learning','Doctrine & mémoire','Bibliothèque institutionnelle gouvernée des doctrines, preuves, règles, scripts, playbooks, restrictions, versions et conflits.','/revenue-command-os/memory-learning','BrainCircuit',110,'revenue_os.knowledge.manage','ready','green','["Doctrine approuvée","Preuves","Scripts","Playbooks","Restrictions","Versions","Conflits","Indexation"]'::jsonb)
on conflict(workspace_key) do update set label=excluded.label,description=excluded.description,href=excluded.href,required_permission=excluded.required_permission,status=excluded.status,contract_scope=excluded.contract_scope,updated_at=timezone('utc',now());

on conflict(code) do update set name=excluded.name,description=excluded.description,owner_role=excluded.owner_role,updated_at=timezone('utc',now());


values('AC-REVENUE-OS-MZ03-DOCTRINE-MEMORY','AC-REVENUE-OS-CANONICAL-2026.07','3.0.0-phase3','shadow','installed',jsonb_build_object('phase',3,'doctrine_count',(select count(*) from public.revenue_os_doctrines),'asset_count',(select count(*) from public.revenue_os_knowledge_assets),'external_execution',false))
on conflict(release_code) do update set module_version=excluded.module_version,status='installed',metadata=excluded.metadata,updated_at=timezone('utc',now());

values('AC-MZ03-INSTALL','knowledge.mz03.installed','Revenue OS Migration','migration','revenue_knowledge_model','success','Mega ZIP 3 Doctrine & Institutional Memory installed in Shadow mode.',jsonb_build_object('release','AC-REVENUE-OS-MZ03-DOCTRINE-MEMORY','external_actions',false))
on conflict(event_id) do nothing;

commit;
