insert into public.revenue_os_doctrines(code,title,summary,knowledge_type,owner_role,department,business_unit_codes,status,confidentiality,version,effective_from,effective_to,next_review_at,review_cycle_days,supersedes_code,applicable_command_families,applicable_segment_codes,applicable_offer_codes,tags,source_authority,content_blocks,rules,evidence_refs,source,created_by_label) values('REV-DOC-001','Doctrine de vérité commerciale','Aucune stratégie ne peut utiliser une donnée commerciale non sourcée comme un fait.','commercial-doctrine','Direction Revenue','Revenue Strategy','["ACADEMY","HOME_SERVICE","FLASHCARDS","CORPORATES"]'::jsonb,'effective','internal','1.0','2026-07-20',null,'2026-10-20',90,null,'["market-sensing","strategy-assembly"]'::jsonb,'[]'::jsonb,'[]'::jsonb,'["commercial-doctrine","revenue-strategy","market-sensing","strategy-assembly"]'::jsonb,'Canonical Revenue Command OS Contract + validated AngelCare operational doctrine','[{"code":"purpose","heading":"Intention stratégique","body":"Aucune stratégie ne peut utiliser une donnée commerciale non sourcée comme un fait.","order":1,"blockType":"principle"},{"code":"application","heading":"Application opérationnelle","body":"Cette doctrine s’applique dès qu’une décision ou une action liée à « Doctrine de vérité commerciale » est préparée, évaluée ou exécutée dans Revenue Command OS.","order":2,"blockType":"procedure"},{"code":"control","heading":"Contrôle obligatoire","body":"La source, la version, le statut, l’autorité et le périmètre doivent être vérifiés avant utilisation par une commande intelligente ou une mission compilée.","order":3,"blockType":"warning"}]'::jsonb,'[{"code":"REV-DOC-001-R1","name":"La donnée la plus récente et approuvée prévaut.","condition":"Whenever this doctrine is applicable","requiredAction":"La donnée la plus récente et approuvée prévaut.","prohibitedAction":"Ignore the approved doctrine or use an unsupported assumption","escalationRole":"Direction Revenue","severity":"high","machineEnforceable":true},{"code":"REV-DOC-001-R2","name":"Une hypothèse doit être marquée comme hypothèse et associée à une méthode de validation.","condition":"Whenever this doctrine is applicable","requiredAction":"Une hypothèse doit être marquée comme hypothèse et associée à une méthode de validation.","prohibitedAction":"Ignore the approved doctrine or use an unsupported assumption","escalationRole":"Direction Revenue","severity":"medium","machineEnforceable":true}]'::jsonb,'["KNW-ASSET-001","KNW-ASSET-002"]'::jsonb,'contract-seed','Revenue OS Migration') on conflict(code) do nothing;
