insert into public.revenue_os_sales_scripts(code,name,channel,stage,segment_codes,offer_codes,objective,opening,body,call_to_action,fallback,prohibited_claims,required_personalization_fields,status,version,owner_role) values('WA-ACADEMY-INTRO','Prise de contact Academy — direction','whatsapp','first-contact','["CRECHE_PRIVATE","PRESCHOOL"]'::jsonb,'["ACADEMY_ONSITE"]'::jsonb,'Obtenir la permission de présenter le catalogue','Bonjour {{contact_name}}, je vous contacte au nom d’AngelCare Academy au sujet de la préparation et de la montée en compétences de votre équipe.','Nous avons structuré des parcours destinés aux crèches et maternelles, réalisables sur site ou avec supports et accès adaptés.','Puis-je vous proposer un échange de 15 minutes pour identifier les priorités de votre établissement ?','Créer une prochaine action interne sans envoyer de message non approuvé.','["Garantie de résultat","Capacité non confirmée","Remise non validée"]'::jsonb,'["contact_name","organization_name","known_priority"]'::jsonb,'approved','1.0','Revenue Communications Lead') on conflict(code) do nothing;
insert into public.revenue_os_sales_scripts(code,name,channel,stage,segment_codes,offer_codes,objective,opening,body,call_to_action,fallback,prohibited_claims,required_personalization_fields,status,version,owner_role) values('WA-CATALOGUE-FOLLOWUP','Suivi après catalogue','whatsapp','catalogue-sent','["CRECHE_PRIVATE","PRESCHOOL"]'::jsonb,'["ACADEMY_ONSITE","FLASHCARDS_PLV"]'::jsonb,'Transformer l’envoi en rendez-vous','Bonjour {{contact_name}}, avez-vous pu parcourir le catalogue transmis ?','Je peux vous orienter directement vers les modules les plus pertinents selon votre équipe, votre calendrier et vos priorités.','Quel créneau vous conviendrait pour un court diagnostic ?','Créer une prochaine action interne sans envoyer de message non approuvé.','["Garantie de résultat","Capacité non confirmée","Remise non validée"]'::jsonb,'["contact_name","organization_name","known_priority"]'::jsonb,'approved','1.0','Revenue Communications Lead') on conflict(code) do nothing;
insert into public.revenue_os_sales_scripts(code,name,channel,stage,segment_codes,offer_codes,objective,opening,body,call_to_action,fallback,prohibited_claims,required_personalization_fields,status,version,owner_role) values('WA-FLASHCARDS-PARTNER','Invitation partenaire Flashcards','whatsapp','first-contact','["CRECHE_PRIVATE","ORTHOPHONIST","MATERNITY_CLINIC"]'::jsonb,'["FLASHCARDS_PLV"]'::jsonb,'Qualifier l’intérêt partenaire','Bonjour {{contact_name}}, AngelCare active un programme partenaire autour de collections éducatives et d’une PLV dédiée.','Le dispositif peut compléter votre expérience familles ou vos outils pédagogiques, sous réserve d’adéquation avec votre établissement.','Souhaitez-vous recevoir la présentation partenaire et les conditions applicables ?','Créer une prochaine action interne sans envoyer de message non approuvé.','["Garantie de résultat","Capacité non confirmée","Remise non validée"]'::jsonb,'["contact_name","organization_name","known_priority"]'::jsonb,'approved','1.0','Revenue Communications Lead') on conflict(code) do nothing;
insert into public.revenue_os_sales_scripts(code,name,channel,stage,segment_codes,offer_codes,objective,opening,body,call_to_action,fallback,prohibited_claims,required_personalization_fields,status,version,owner_role) values('EMAIL-ACADEMY-DIAGNOSTIC','Email rendez-vous diagnostic Academy','email','meeting-generation','["CRECHE_PRIVATE","PRESCHOOL"]'::jsonb,'["ACADEMY_ONSITE"]'::jsonb,'Confirmer un échange de direction','Objet : Préparation de votre équipe — échange AngelCare Academy','Nous proposons un diagnostic court pour identifier les formations et supports réellement utiles à votre établissement. Le rendez-vous ne vaut pas engagement et permet de cadrer priorité, format et calendrier.','Répondez avec deux créneaux ou contactez notre équipe.','Créer une prochaine action interne sans envoyer de message non approuvé.','["Garantie de résultat","Capacité non confirmée","Remise non validée"]'::jsonb,'["contact_name","organization_name","known_priority"]'::jsonb,'approved','1.0','Revenue Communications Lead') on conflict(code) do nothing;
insert into public.revenue_os_sales_scripts(code,name,channel,stage,segment_codes,offer_codes,objective,opening,body,call_to_action,fallback,prohibited_claims,required_personalization_fields,status,version,owner_role) values('PHONE-QUALIFICATION-B2B','Appel de qualification B2B','phone','qualification','["CRECHE_PRIVATE","PRESCHOOL","CORPORATE"]'::jsonb,'["ACADEMY_ONSITE","CORPORATE_CARE"]'::jsonb,'Qualifier besoin, autorité, timing et prochaine étape','Bonjour, je suis {{agent_name}} d’AngelCare. Est-ce un bon moment pour deux questions rapides ?','Comprendre l’organisation, l’équipe, le besoin prioritaire, le calendrier et le circuit de décision.','Proposer une prochaine étape datée et envoyer uniquement les ressources pertinentes.','Créer une prochaine action interne sans envoyer de message non approuvé.','["Garantie de résultat","Capacité non confirmée","Remise non validée"]'::jsonb,'["contact_name","organization_name","known_priority"]'::jsonb,'approved','1.0','Revenue Communications Lead') on conflict(code) do nothing;
