insert into public.revenue_os_objection_patterns(code,objection,category,segment_codes,offer_codes,diagnostic_questions,response_framework,evidence_refs,escalation_trigger,prohibited_response,status) values('OBJ-PRICE','« C’est trop cher »','price','["CRECHE_PRIVATE","PRESCHOOL","CORPORATE"]'::jsonb,'["ACADEMY_ONSITE","ACADEMY_ELEARNING"]'::jsonb,'["Qu’est-ce qui vous fait dire cela ?","Quelle condition changerait votre décision ?","Qui doit être impliqué pour décider ?"]'::jsonb,'["Identifier la comparaison, le budget, la valeur manquante et le périmètre.","Reformuler la réponse du prospect.","Proposer une prochaine étape adaptée et mesurable."]'::jsonb,'["KNW-ASSET-016"]'::jsonb,'Escalader si l’objection implique prix exceptionnel, engagement contractuel ou risque sensible.','Promettre un résultat, inventer une remise ou contester agressivement le prospect.','approved') on conflict(code) do nothing;
